sql:
SELECT COUNT(*) AS completed_time_steps
FROM time_steps
WHERE agent_id = 0 AND status = 'completed';

SELECT agent_name 
FROM agents 
ORDER BY agent_name;

SELECT avg_action_dist
FROM avg_action_dist
WHERE time_step_id = 0;

SELECT human_obs
FROM human_obs
WHERE observer_id = 1;

SELECT original_reward, created_at
FROM original_rewards
WHERE reward_type = 'positive';

SELECT AVG(original_reward) AS avg_original_reward
FROM original_rewards
WHERE time_step_id = 1;

SELECT duration
FROM time_steps
WHERE status = 'completed';
